import type { CareerQuestion } from "./rrt-questions";

export const sonographyQuestionsBatch4: CareerQuestion[] = [
  { id: "sono-206", stem: "Grating lobe artifacts are produced by:", options: ["Multi-element array transducers due to regular spacing of elements","Single-element transducers","Continuous wave Doppler only","Patient motion"], correctIndex: 0, rationale: "Grating lobes are off-axis energy beams produced by the regular periodic spacing of elements in array transducers. They can create false echoes similar to side lobe artifacts.", difficulty: 4, category: "Ultrasound Physics & Instrumentation", topic: "Artifacts" },
  { id: "sono-207", stem: "B-mode (brightness mode) displays:", options: ["A 2D cross-sectional image with echo amplitude represented as brightness","Only time-motion data","Doppler frequency shifts","3D volumetric data"], correctIndex: 0, rationale: "B-mode creates a 2D image by assigning brightness levels to echo amplitudes at their calculated positions. It is the standard real-time imaging mode.", difficulty: 1, category: "Ultrasound Physics & Instrumentation", topic: "Imaging Modes" },
  { id: "sono-208", stem: "M-mode is most useful for evaluating:", options: ["Rapidly moving structures such as cardiac valves over time","Static abdominal organs","Vascular flow velocity","3D fetal anatomy"], correctIndex: 0, rationale: "M-mode (motion mode) displays a single beam line over time, showing motion of structures along that line. Excellent temporal resolution for valve motion and fetal heart rate.", difficulty: 1, category: "Ultrasound Physics & Instrumentation", topic: "Imaging Modes" },
  { id: "sono-209", stem: "The Nyquist limit equals:", options: ["One half of the pulse repetition frequency","Twice the PRF","The transducer frequency","The frame rate"], correctIndex: 0, rationale: "Nyquist limit = PRF/2. It is the maximum Doppler shift that can be accurately displayed without aliasing in pulsed Doppler and color Doppler.", difficulty: 2, category: "Ultrasound Physics & Instrumentation", topic: "Doppler Principles" },
  { id: "sono-210", stem: "Continuous wave (CW) Doppler differs from pulsed wave (PW) in that CW:", options: ["Has no range resolution but can measure very high velocities without aliasing","Provides precise depth localization","Creates a 2D image","Cannot detect Doppler shifts"], correctIndex: 0, rationale: "CW uses separate transmit and receive elements continuously. No Nyquist limit allows high velocity measurement, but depth localization (range resolution) is lost.", difficulty: 2, category: "Ultrasound Physics & Instrumentation", topic: "Doppler Principles" },
  { id: "sono-211", stem: "The wall filter in Doppler eliminates:", options: ["Low-frequency high-amplitude signals from vessel wall motion (clutter)","High-velocity blood flow signals","All Doppler signals","Background noise only"], correctIndex: 0, rationale: "The wall (high-pass) filter removes low-frequency, high-amplitude clutter from vessel walls and tissue motion. If set too high, it may eliminate slow flow signals.", difficulty: 2, category: "Ultrasound Physics & Instrumentation", topic: "Doppler Principles" },
  { id: "sono-212", stem: "Spectral Doppler sample volume (gate) size affects:", options: ["The volume of blood flow being sampled — larger gate samples more flow velocities","Image resolution only","The transmit frequency","Color Doppler box size"], correctIndex: 0, rationale: "Sample volume size determines how much of the vessel lumen is interrogated. Small gate in the center shows laminar plug flow; large gate shows the full velocity profile.", difficulty: 2, category: "Ultrasound Physics & Instrumentation", topic: "Doppler Principles" },
  { id: "sono-213", stem: "The Bernoulli equation in hemodynamics relates:", options: ["Pressure gradient across a stenosis to peak velocity","Vessel diameter to flow volume","Heart rate to cardiac output","Viscosity to Reynolds number"], correctIndex: 0, rationale: "Simplified Bernoulli: ΔP = 4V². It estimates pressure gradient from peak velocity measured by Doppler. Used extensively in echocardiography for valvular assessment.", difficulty: 3, category: "SPI (Sonography Principles & Instrumentation)", topic: "Hemodynamics" },
  { id: "sono-214", stem: "Reynolds number predicts:", options: ["Whether flow will be laminar or turbulent in a vessel","The Doppler shift frequency","Acoustic impedance","Beam attenuation"], correctIndex: 0, rationale: "Reynolds number considers velocity, vessel diameter, density, and viscosity. Re >2000 suggests turbulent flow. Used to predict flow disturbance at stenoses and bifurcations.", difficulty: 3, category: "SPI (Sonography Principles & Instrumentation)", topic: "Hemodynamics" },
  { id: "sono-215", stem: "Poiseuille's law states that flow is proportional to:", options: ["The fourth power of the vessel radius","The square of vessel length","Fluid viscosity","Vessel wall thickness"], correctIndex: 0, rationale: "Q = (πr⁴ΔP)/(8ηL). Flow is proportional to the fourth power of radius. Small decreases in vessel diameter dramatically reduce flow. Viscosity and length inversely affect flow.", difficulty: 4, category: "SPI (Sonography Principles & Instrumentation)", topic: "Hemodynamics" },
  { id: "sono-216", stem: "The continuity equation states that in a rigid tube:", options: ["Flow volume is constant; if area decreases, velocity must increase","Velocity remains constant regardless of area","Pressure is always equal throughout","Flow reverses at narrowing"], correctIndex: 0, rationale: "A₁V₁ = A₂V₂. Flow volume is conserved. At a stenosis (smaller area), velocity increases proportionally. This principle underlies Doppler velocity measurement at stenoses.", difficulty: 3, category: "SPI (Sonography Principles & Instrumentation)", topic: "Hemodynamics" },
  { id: "sono-217", stem: "Hepatic hemangioma follow-up for a typical small (<3cm) lesion involves:", options: ["No follow-up needed if appearance is classic on imaging","CT angiography every 3 months","Surgical resection","Liver biopsy"], correctIndex: 0, rationale: "Classic small hemangiomas with typical features (hyperechoic, well-defined, no growth) on ultrasound need no follow-up. Atypical or large lesions may need contrast CT/MRI.", difficulty: 2, category: "Abdominal Sonography", topic: "Liver" },
  { id: "sono-218", stem: "The ligamentum venosum is a remnant of the:", options: ["Ductus venosus","Umbilical vein","Ductus arteriosus","Umbilical artery"], correctIndex: 0, rationale: "The ligamentum venosum is the remnant of the fetal ductus venosus, which shunted oxygenated blood from the umbilical vein directly to the IVC, bypassing the liver sinusoids.", difficulty: 2, category: "Abdominal Sonography", topic: "Liver" },
  { id: "sono-219", stem: "Periportal cuffing on liver ultrasound is seen in:", options: ["Conditions causing edema around portal triads such as hepatitis and heart failure","Normal liver","Fatty liver only","Cirrhosis without complications"], correctIndex: 0, rationale: "Periportal cuffing (echogenic or hypoechoic halos around portal triads) occurs with edema from hepatitis, CHF, transplant rejection, or lymphatic obstruction.", difficulty: 3, category: "Abdominal Sonography", topic: "Liver" },
  { id: "sono-220", stem: "Hepatic cirrhosis findings on ultrasound include:", options: ["Surface nodularity, coarsened echotexture, caudate lobe enlargement, and ascites","Smooth liver surface with normal echotexture","Diffuse decreased echogenicity","Single large cyst"], correctIndex: 0, rationale: "Cirrhosis: nodular liver surface, coarsened heterogeneous echotexture, right lobe shrinkage with caudate/left lobe hypertrophy, portal hypertension signs, and ascites.", difficulty: 2, category: "Abdominal Sonography", topic: "Liver" },
  { id: "sono-221", stem: "TIPS (transjugular intrahepatic portosystemic shunt) patency is assessed by:", options: ["Doppler showing flow velocity of 50-200 cm/s within the stent with hepatofugal portal flow direction","Absence of any flow in the shunt","Reversal of flow in the hepatic artery","B-mode appearance only"], correctIndex: 0, rationale: "TIPS patency: stent velocities 50-200 cm/s. Velocity <50 or >200 cm/s suggests dysfunction. Flow direction should be hepatofugal (away from liver) in the main portal vein.", difficulty: 4, category: "Abdominal Sonography", topic: "Liver" },
  { id: "sono-222", stem: "Gallbladder wall thickening (>3mm) can be caused by all EXCEPT:", options: ["Recent fasting state","Acute cholecystitis","Hepatitis","Ascites"], correctIndex: 0, rationale: "GB wall thickening is seen in cholecystitis, hepatitis, CHF, hypoalbuminemia, ascites, and renal failure. A properly fasting patient with isolated wall thickening needs clinical correlation.", difficulty: 3, category: "Abdominal Sonography", topic: "Gallbladder/Biliary" },
  { id: "sono-223", stem: "Emphysematous cholecystitis is suggested by:", options: ["Gas within the gallbladder wall producing dirty shadowing and ring-down artifact","Simple gallstones without shadowing","Sludge in the gallbladder","Thin-walled distended gallbladder"], correctIndex: 0, rationale: "Emphysematous cholecystitis: gas in the GB wall from gas-forming organisms. Shows echogenic foci with dirty shadowing/ring-down in the wall. Surgical emergency with high perforation risk.", difficulty: 4, category: "Abdominal Sonography", topic: "Gallbladder/Biliary" },
  { id: "sono-224", stem: "Choledochal cyst is:", options: ["Congenital cystic dilation of the bile duct, most common in female children","Acquired gallbladder cyst","Pancreatic pseudocyst","Hepatic cyst"], correctIndex: 0, rationale: "Choledochal cysts are congenital bile duct dilations classified by Todani (Types I-V). Type I (fusiform CBD dilation) is most common. Risk of cholangiocarcinoma.", difficulty: 3, category: "Abdominal Sonography", topic: "Gallbladder/Biliary" },
  { id: "sono-225", stem: "Caroli disease is characterized by:", options: ["Segmental cystic dilation of intrahepatic bile ducts","Dilation of the CBD only","Gallbladder agenesis","Hepatic vein thrombosis"], correctIndex: 0, rationale: "Caroli disease (Type V choledochal cyst): multiple cystic dilations of the intrahepatic bile ducts. The 'central dot sign' (portal vein radicle within dilated duct) is characteristic.", difficulty: 4, category: "Abdominal Sonography", topic: "Gallbladder/Biliary" },
  { id: "sono-226", stem: "A horseshoe kidney is identified when:", options: ["The lower poles are fused across the midline anterior to the aorta and IVC","Two separate kidneys are in the pelvis","One kidney is absent","Both kidneys are in the thorax"], correctIndex: 0, rationale: "Horseshoe kidney: lower poles connected by an isthmus of functioning tissue or fibrous band anterior to the great vessels. Usually located lower than normal due to IMA preventing ascent.", difficulty: 2, category: "Abdominal Sonography", topic: "Kidneys" },
  { id: "sono-227", stem: "Renal artery stenosis can cause:", options: ["Renovascular hypertension and renal atrophy of the affected kidney","Bilateral renal enlargement","Hydronephrosis","Renal cysts"], correctIndex: 0, rationale: "RAS reduces renal perfusion, activating RAAS → hypertension. Chronic ischemia leads to renal atrophy. Size discrepancy >2cm between kidneys should prompt RAS evaluation.", difficulty: 2, category: "Abdominal Sonography", topic: "Kidneys" },
  { id: "sono-228", stem: "The Bosniak classification system categorizes:", options: ["Renal cystic masses based on imaging features to predict malignancy risk","Liver masses","Ovarian cysts","Pancreatic cysts"], correctIndex: 0, rationale: "Bosniak classifies renal cysts: I (simple), II (minimally complex), IIF (follow-up), III (indeterminate, 50% malignant), IV (clearly malignant). Based on CT/MRI features.", difficulty: 3, category: "Abdominal Sonography", topic: "Kidneys" },
  { id: "sono-229", stem: "Xanthogranulomatous pyelonephritis (XGP) typically presents as:", options: ["Enlarged non-functioning kidney with obstructing calculus and hypoechoic parenchymal masses replacing normal tissue","Small hyperechoic kidney","Bilateral hydronephrosis","Normal kidney with cortical cyst"], correctIndex: 0, rationale: "XGP: chronic destructive granulomatous infection, usually unilateral with staghorn calculus. The kidney is enlarged with parenchyma replaced by inflammatory masses. Often requires nephrectomy.", difficulty: 4, category: "Abdominal Sonography", topic: "Kidneys" },
  { id: "sono-230", stem: "An ectopic pelvic kidney is found:", options: ["In the pelvis, failing to ascend during embryonic development","In the thorax","Behind the spleen","Within the liver"], correctIndex: 0, rationale: "Pelvic kidney results from failure of normal embryonic ascent. It is usually functional but may have an abnormal vascular supply and is prone to obstruction.", difficulty: 1, category: "Abdominal Sonography", topic: "Kidneys" },
  { id: "sono-231", stem: "Nutcracker syndrome involves:", options: ["Compression of the left renal vein between the SMA and aorta","Right renal artery occlusion","IVC compression by the liver","Bilateral ureteral obstruction"], correctIndex: 0, rationale: "Nutcracker syndrome: the left renal vein is compressed between the SMA (anterior) and aorta (posterior), causing venous hypertension, hematuria, and flank pain.", difficulty: 3, category: "Abdominal Sonography", topic: "Kidneys" },
  { id: "sono-232", stem: "The normal urinary bladder wall thickness should not exceed:", options: ["3 mm when distended","1 mm","6 mm when distended","10 mm when distended"], correctIndex: 0, rationale: "Normal bladder wall is ≤3mm when distended. Wall thickening suggests cystitis, outlet obstruction (trabeculation), neurogenic bladder, or neoplasm.", difficulty: 2, category: "Abdominal Sonography", topic: "Bladder" },
  { id: "sono-233", stem: "Post-void residual volume greater than _____ is considered abnormal:", options: ["100 mL","10 mL","500 mL","1 L"], correctIndex: 0, rationale: "Post-void residual >100 mL (or >200 mL in some guidelines) is considered elevated. Causes include bladder outlet obstruction (BPH), neurogenic bladder, and medication effects.", difficulty: 2, category: "Abdominal Sonography", topic: "Bladder" },
  { id: "sono-234", stem: "Ureteral jets on color Doppler are:", options: ["Periodic bursts of urine flow from the ureteral orifices into the bladder","Arterial flow in the bladder wall","Venous return from the bladder","Artifact from patient movement"], correctIndex: 0, rationale: "Ureteral jets are visible on color Doppler as intermittent flow from ureteral orifices into the bladder. Absence of a jet on one side may suggest obstruction.", difficulty: 2, category: "Abdominal Sonography", topic: "Bladder" },
  { id: "sono-235", stem: "A neuroblastoma in a child arises from:", options: ["The adrenal medulla or sympathetic chain","The kidney cortex","The liver parenchyma","The pancreas"], correctIndex: 0, rationale: "Neuroblastoma is the most common extracranial solid tumor in children. It arises from neural crest cells in the adrenal medulla or sympathetic chain. Appears as a heterogeneous suprarenal mass.", difficulty: 2, category: "Abdominal Sonography", topic: "Adrenal" },
  { id: "sono-236", stem: "Pheochromocytoma on ultrasound typically appears as:", options: ["Well-defined solid suprarenal mass that may be heterogeneous with areas of hemorrhage","Small calcified adrenal gland","Bilateral adrenal atrophy","Anechoic adrenal cyst"], correctIndex: 0, rationale: "Pheochromocytoma: catecholamine-secreting tumor of adrenal medulla. Appears as a solid suprarenal mass, often heterogeneous from hemorrhage/necrosis. 'Rule of 10s' (10% bilateral, malignant, extra-adrenal).", difficulty: 3, category: "Abdominal Sonography", topic: "Adrenal" },
  { id: "sono-237", stem: "The normal endometrial thickness in a postmenopausal woman not on HRT should not exceed:", options: ["5 mm","10 mm","15 mm","20 mm"], correctIndex: 0, rationale: "Endometrial thickness >5mm (double-layer) in a postmenopausal woman with vaginal bleeding warrants further evaluation (biopsy) to exclude endometrial carcinoma.", difficulty: 2, category: "OB/GYN Sonography", topic: "Gynecology" },
  { id: "sono-238", stem: "Endometrioma (chocolate cyst) on ultrasound shows:", options: ["Homogeneous low-level internal echoes (ground glass) without internal vascularity","Simple anechoic cyst","Solid mass with high vascularity","Multiple septations with mural nodules"], correctIndex: 0, rationale: "Endometriomas contain old blood products, producing the characteristic 'ground glass' homogeneous low-level echoes. They are typically round with smooth walls. No internal color flow.", difficulty: 2, category: "OB/GYN Sonography", topic: "Gynecology" },
  { id: "sono-239", stem: "A dermoid cyst (mature cystic teratoma) may show:", options: ["Echogenic mural nodule (Rokitansky nodule), fat-fluid level, and 'tip of the iceberg' sign","Simple anechoic appearance","Completely solid homogeneous mass","Color Doppler flow throughout"], correctIndex: 0, rationale: "Dermoids contain fat, hair, and teeth. Characteristic findings: echogenic Rokitansky nodule, fat-fluid level, dermoid mesh (hair), and tip-of-the-iceberg sign from shadowing by sebaceous material.", difficulty: 3, category: "OB/GYN Sonography", topic: "Gynecology" },
  { id: "sono-240", stem: "Ovarian torsion findings include:", options: ["Enlarged ovary with peripheral follicles (string of pearls), absent venous flow, and whirlpool sign of the pedicle","Small atrophic ovary","Normal ovary with corpus luteum","Bilateral ovarian cysts"], correctIndex: 0, rationale: "Torsion: enlarged edematous ovary, peripheral follicles, absent/decreased flow (venous first, then arterial), and whirlpool sign of the twisted vascular pedicle on color Doppler.", difficulty: 3, category: "OB/GYN Sonography", topic: "Gynecology" },
  { id: "sono-241", stem: "The most common uterine neoplasm is:", options: ["Leiomyoma (fibroid)","Endometrial carcinoma","Cervical carcinoma","Uterine sarcoma"], correctIndex: 0, rationale: "Leiomyomas are the most common uterine tumors. Sonographically: well-defined hypoechoic masses, may calcify (shadowing), can be submucosal, intramural, or subserosal.", difficulty: 1, category: "OB/GYN Sonography", topic: "Gynecology" },
  { id: "sono-242", stem: "A submucosal fibroid is important because it:", options: ["Distorts the endometrial cavity and can cause abnormal uterine bleeding and infertility","Is always malignant","Has no clinical significance","Only occurs after menopause"], correctIndex: 0, rationale: "Submucosal fibroids project into the endometrial cavity, causing heavy menstrual bleeding, infertility, and pregnancy complications. They may be treated with hysteroscopic resection.", difficulty: 2, category: "OB/GYN Sonography", topic: "Gynecology" },
  { id: "sono-243", stem: "Adenomyosis on ultrasound appears as:", options: ["Diffusely enlarged uterus with heterogeneous myometrium and myometrial cysts","Well-defined pedunculated mass","Normal-sized uterus with thin endometrium","Calcified uterine wall"], correctIndex: 0, rationale: "Adenomyosis: endometrial tissue within the myometrium. Shows asymmetric myometrial thickening, heterogeneous echotexture, myometrial cysts, and poorly defined endometrial-myometrial junction.", difficulty: 3, category: "OB/GYN Sonography", topic: "Gynecology" },
  { id: "sono-244", stem: "Polycystic ovarian syndrome (PCOS) ultrasound criteria include:", options: ["≥12 follicles per ovary (2-9mm) or ovarian volume >10 mL","Single dominant follicle >20mm","Ovarian volume <5 mL","Absence of follicles"], correctIndex: 0, rationale: "Rotterdam criteria (ultrasound): ≥12 peripheral follicles (2-9mm) per ovary or ovarian volume >10mL. Combined with clinical/lab findings (oligo-anovulation, hyperandrogenism).", difficulty: 2, category: "OB/GYN Sonography", topic: "Gynecology" },
  { id: "sono-245", stem: "An IUD on ultrasound appears as:", options: ["Highly echogenic linear or T-shaped structure within the endometrial cavity with possible shadowing","Hypoechoic mass in the myometrium","Anechoic structure in the cervix","Absent from ultrasound visualization"], correctIndex: 0, rationale: "IUDs (copper or hormonal) appear as bright echogenic structures in the endometrial cavity. Proper position: fundal. Malposition or perforation requires evaluation.", difficulty: 1, category: "OB/GYN Sonography", topic: "Gynecology" },
  { id: "sono-246", stem: "The normal ovarian volume in a reproductive-age woman is approximately:", options: ["Up to 10 mL","Up to 30 mL","Up to 50 mL","Less than 1 mL"], correctIndex: 0, rationale: "Normal ovarian volume is ≤10 mL (or ~20 mL during ovulation with a dominant follicle). Calculated as 0.523 × L × W × H. Postmenopausal ovaries are typically <5 mL.", difficulty: 2, category: "OB/GYN Sonography", topic: "Gynecology" },
  { id: "sono-247", stem: "Heterotopic pregnancy refers to:", options: ["Simultaneous intrauterine and ectopic pregnancies","Twin pregnancy within the uterus","Ectopic pregnancy in the cervix","Molar pregnancy with coexisting fetus"], correctIndex: 0, rationale: "Heterotopic pregnancy: coexisting IUP and ectopic pregnancy. Rare naturally (1:30,000) but more common with ART (1:100). Do not assume ectopic is excluded by presence of IUP in ART patients.", difficulty: 3, category: "OB/GYN Sonography", topic: "First Trimester" },
  { id: "sono-248", stem: "The interstitial (cornual) ectopic pregnancy is identified by:", options: ["Gestational sac in the myometrium at the uterine cornua surrounded by <5mm of myometrium","Gestational sac in the cervix","Normal intrauterine gestational sac","Adnexal ring in the cul-de-sac"], correctIndex: 0, rationale: "Interstitial ectopic: GS in the interstitial portion of the tube within the myometrium. Thin surrounding myometrium (<5mm) and the 'interstitial line sign' help diagnose this dangerous variant.", difficulty: 4, category: "OB/GYN Sonography", topic: "First Trimester" },
  { id: "sono-249", stem: "Twin peak sign (lambda sign) indicates:", options: ["Dichorionic twin pregnancy","Monochorionic monoamniotic twins","Conjoined twins","Singleton pregnancy"], correctIndex: 0, rationale: "Twin peak (lambda) sign: triangular projection of placental tissue between the layers of the dividing membrane. Indicates dichorionic placentation. Best seen in first trimester.", difficulty: 2, category: "OB/GYN Sonography", topic: "Second/Third Trimester" },
  { id: "sono-250", stem: "Monochorionic monoamniotic twins carry the unique risk of:", options: ["Cord entanglement because there is no dividing membrane","Twin-to-twin transfusion only","Placenta previa","Gestational diabetes"], correctIndex: 0, rationale: "MCMA twins share one amniotic sac with no membrane separation. Cord entanglement is the primary risk, causing sudden fetal demise. Close surveillance is essential.", difficulty: 3, category: "OB/GYN Sonography", topic: "Second/Third Trimester" },
  { id: "sono-251", stem: "Twin-to-twin transfusion syndrome (TTTS) occurs in:", options: ["Monochorionic diamniotic twins with unbalanced placental vascular anastomoses","Dichorionic twins","Singleton pregnancies","All twin pregnancies"], correctIndex: 0, rationale: "TTTS occurs in MCDA twins when arteriovenous anastomoses in the shared placenta cause unequal blood flow. Donor twin: oligohydramnios, IUGR. Recipient: polyhydramnios, hydrops.", difficulty: 3, category: "OB/GYN Sonography", topic: "Second/Third Trimester" },
  { id: "sono-252", stem: "A succenturiate placental lobe is:", options: ["An accessory lobe of placenta connected by vessels through the membranes","A normal variant of placental shape","A molar pregnancy","An abruption"], correctIndex: 0, rationale: "Succenturiate lobe: accessory placental lobe connected to the main placenta by vessels within the membranes. Risk of vasa previa, retained placenta, and postpartum hemorrhage.", difficulty: 3, category: "OB/GYN Sonography", topic: "Second/Third Trimester" },
  { id: "sono-253", stem: "Placenta accreta spectrum on prenatal ultrasound may show:", options: ["Loss of the clear retroplacental hypoechoic zone with lacunae (Swiss cheese appearance)","Normal retroplacental space","Thin placenta","Placenta in the fundus only"], correctIndex: 0, rationale: "Placenta accreta: loss of normal retroplacental clear space, placental lacunae (turbulent flow), thinning/disruption of uterine-bladder interface. Risk factors: prior C-sections, placenta previa.", difficulty: 4, category: "OB/GYN Sonography", topic: "Second/Third Trimester" },
  { id: "sono-254", stem: "Fetal cystic hygroma is:", options: ["Lymphatic malformation typically in the posterior cervical region associated with Turner syndrome","Normal skin fold","Cerebral ventricle dilation","Cardiac defect"], correctIndex: 0, rationale: "Cystic hygroma: septated cystic mass at the posterior neck/nuchal region from lymphatic obstruction. Strong association with chromosomal abnormalities, especially Turner syndrome (45,X).", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-255", stem: "Anencephaly is diagnosed on ultrasound when:", options: ["There is absence of the cranial vault above the orbits","The ventricles are dilated","There is a small head with normal calvarium","The cerebellum is absent"], correctIndex: 0, rationale: "Anencephaly: absence of cranial vault and cerebral hemispheres above the orbits. Diagnosed in the first trimester (absent calvarium) or second trimester. Lethal condition.", difficulty: 1, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-256", stem: "Spina bifida on ultrasound shows:", options: ["Splaying of posterior ossification centers of the vertebra with lemon and banana signs in the skull","Normal spine alignment","Widened skull with cherry appearance","Absent kidneys"], correctIndex: 0, rationale: "Open spina bifida: widened posterior vertebral elements. Associated intracranial signs: lemon-shaped skull (frontal bossing) and banana-shaped cerebellum (Chiari II malformation).", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-257", stem: "The lemon sign in fetal imaging refers to:", options: ["Indentation of the frontal bones giving the skull a lemon shape on axial view","Oval-shaped cerebellum","Round fetal head","Absent nasal bone"], correctIndex: 0, rationale: "Lemon sign: scalloping/concavity of the frontal bones on axial view. Associated with open spina bifida (Chiari II malformation) and occasionally other anomalies.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-258", stem: "Gastroschisis differs from omphalocele in that gastroschisis:", options: ["Has no covering membrane and the defect is typically to the right of the umbilicus","Has a membrane covering the herniated organs","Is associated with chromosomal abnormalities","Includes the liver in the herniation"], correctIndex: 0, rationale: "Gastroschisis: paraumbilical (usually right) defect without membrane. Free-floating bowel in amniotic fluid. Omphalocele: midline defect with membrane covering, associated with aneuploidy.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-259", stem: "Bilateral renal agenesis (Potter sequence) results in:", options: ["Severe oligohydramnios, pulmonary hypoplasia, and limb deformities","Polyhydramnios","Normal amniotic fluid","Fetal macrosomia"], correctIndex: 0, rationale: "Bilateral renal agenesis: no fetal kidneys → no urine production → severe oligohydramnios → pulmonary hypoplasia and limb compression deformities. Lethal condition.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-260", stem: "Carotid intima-media thickness (IMT) measurement is used for:", options: ["Assessing subclinical atherosclerosis and cardiovascular risk","Diagnosing carotid dissection","Measuring carotid artery diameter","Evaluating carotid body tumors"], correctIndex: 0, rationale: "IMT is measured on the far wall of the distal CCA. Increased IMT (>0.9-1.0mm) indicates subclinical atherosclerosis and increased cardiovascular risk.", difficulty: 2, category: "Vascular Sonography", topic: "Carotid Doppler" },
  { id: "sono-261", stem: "Carotid body tumor (paraganglioma) on ultrasound appears as:", options: ["Hypervascular solid mass at the carotid bifurcation splaying the ICA and ECA","Cystic mass in the parotid gland","Thyroid nodule","Lymph node in the posterior triangle"], correctIndex: 0, rationale: "Carotid body tumors arise from chemoreceptor cells at the bifurcation. They splay the ICA and ECA (lyre sign), are solid, and demonstrate intense vascularity on color Doppler.", difficulty: 3, category: "Vascular Sonography", topic: "Carotid Doppler" },
  { id: "sono-262", stem: "Normal hepatic artery waveform shows:", options: ["Low-resistance flow with continuous forward diastolic flow","High-resistance flow with reversed diastolic flow","No diastolic flow","Venous-type continuous flow"], correctIndex: 0, rationale: "The hepatic artery supplies a vital organ and shows low-resistance flow with maintained forward diastolic flow. RI typically 0.55-0.70. Elevated RI may indicate transplant rejection.", difficulty: 2, category: "Vascular Sonography", topic: "Abdominal Doppler" },
  { id: "sono-263", stem: "Portal vein thrombosis on ultrasound shows:", options: ["Echogenic material within the portal vein with absent or reduced flow on color Doppler","Normal portal venous flow","Increased portal vein velocity","Portal vein aneurysm"], correctIndex: 0, rationale: "PVT: echogenic thrombus in the portal vein. Acute thrombus may be hypoechoic and expand the vein. Chronic may show cavernous transformation (collateral vessels replacing the portal vein).", difficulty: 2, category: "Vascular Sonography", topic: "Abdominal Doppler" },
  { id: "sono-264", stem: "Cavernous transformation of the portal vein represents:", options: ["Periportal collateral vessels that develop after chronic portal vein occlusion","Normal variant of the portal vein","Portal vein aneurysm","Hepatic artery pseudoaneurysm"], correctIndex: 0, rationale: "Cavernous transformation: multiple small tortuous collateral channels in the porta hepatis that form after chronic PVT. They replace the main portal vein and show venous flow on Doppler.", difficulty: 3, category: "Vascular Sonography", topic: "Abdominal Doppler" },
  { id: "sono-265", stem: "Normal hepatic vein waveform is:", options: ["Triphasic pulsatile waveform reflecting right atrial pressure changes","Continuous non-pulsatile flow","High-velocity arterial flow","No detectable flow"], correctIndex: 0, rationale: "Hepatic veins show triphasic flow (two phases toward heart, one brief reversal) reflecting cardiac cycle. Loss of pulsatility (monophasic) may indicate cirrhosis or hepatic congestion.", difficulty: 2, category: "Vascular Sonography", topic: "Abdominal Doppler" },
  { id: "sono-266", stem: "An arteriovenous fistula (AVF) for dialysis is evaluated for:", options: ["Flow velocity, volume flow rate, stenosis, and maturation adequacy","Color only","B-mode diameter alone","Patient weight"], correctIndex: 0, rationale: "AVF assessment: access flow volume (>600 mL/min adequate), stenosis (PSV ratio >2:1), diameter, depth, and maturation. Failing access shows low volume flow or high-grade stenosis.", difficulty: 3, category: "Vascular Sonography", topic: "Dialysis Access" },
  { id: "sono-267", stem: "Steal syndrome in a dialysis AVF is characterized by:", options: ["Reversed flow in the artery distal to the fistula causing hand ischemia","Increased flow in all directions","Normal arterial waveforms","Venous insufficiency only"], correctIndex: 0, rationale: "Steal syndrome: arterial blood flows retrograde past the fistula into the low-resistance access, depriving the distal hand of perfusion. Causes ischemic pain, numbness, tissue loss.", difficulty: 3, category: "Vascular Sonography", topic: "Dialysis Access" },
  { id: "sono-268", stem: "A Baker's cyst (popliteal cyst) communicates with:", options: ["The knee joint through the gastrocnemius-semimembranosus bursa","The popliteal artery","The tibial nerve","The femoral vein"], correctIndex: 0, rationale: "Baker's cyst is a fluid collection in the gastrocnemius-semimembranosus bursa communicating with the knee joint. Appears as an anechoic or complex cystic mass in the popliteal fossa.", difficulty: 2, category: "Small Parts & Superficial", topic: "Musculoskeletal" },
  { id: "sono-269", stem: "Plantar fasciitis on ultrasound shows:", options: ["Thickened hypoechoic plantar fascia (>4mm) at the calcaneal insertion","Normal thin echogenic fascia","Calcified mass in the midfoot","Fluid collection around the Achilles tendon"], correctIndex: 0, rationale: "Normal plantar fascia is <4mm thick at the calcaneal attachment. Plantar fasciitis: thickened (>4mm), hypoechoic, and may show perifascial edema or calcific enthesopathy.", difficulty: 2, category: "Small Parts & Superficial", topic: "Musculoskeletal" },
  { id: "sono-270", stem: "Tendon tears on ultrasound are characterized by:", options: ["Hypoechoic or anechoic gap in the tendon fibers with possible retraction of torn ends","Increased tendon echogenicity","Normal fibrillar pattern","Calcification only"], correctIndex: 0, rationale: "Complete tears show anechoic gap with retracted tendon ends. Partial tears show focal hypoechoic defects within the tendon. Dynamic scanning helps assess extent.", difficulty: 2, category: "Small Parts & Superficial", topic: "Musculoskeletal" },
  { id: "sono-271", stem: "A ganglion cyst on ultrasound appears as:", options: ["Well-defined anechoic or hypoechoic cystic mass adjacent to a joint or tendon sheath","Solid intramuscular mass","Calcified mass with shadowing","Hyperechoic fatty mass"], correctIndex: 0, rationale: "Ganglion cysts are mucin-filled cysts arising from joint capsules or tendon sheaths. They appear as well-defined, anechoic/hypoechoic, lobulated cystic masses, often near the wrist.", difficulty: 1, category: "Small Parts & Superficial", topic: "Musculoskeletal" },
  { id: "sono-272", stem: "Normal lymph nodes on ultrasound show:", options: ["Oval shape with an echogenic fatty hilum and hilar blood flow","Round shape without hilum","Completely anechoic","Calcified with shadowing"], correctIndex: 0, rationale: "Benign lymph nodes are typically oval (L/S ratio >2), with an echogenic hilum and hilar vascularity. Suspicious features: round shape, loss of hilum, cortical thickening, peripheral vascularity.", difficulty: 1, category: "Small Parts & Superficial", topic: "Lymph Nodes" },
  { id: "sono-273", stem: "Suspicious lymph node features suggesting malignancy include:", options: ["Round shape, absent hilum, cortical thickening, and peripheral or mixed vascularity","Oval shape with echogenic hilum","Hilar blood flow pattern","Small size <5mm"], correctIndex: 0, rationale: "Malignant nodes tend to be round (L/S <2), lose the fatty hilum, have thickened cortex, and show peripheral or chaotic vascularity rather than orderly hilar flow.", difficulty: 2, category: "Small Parts & Superficial", topic: "Lymph Nodes" },
  { id: "sono-274", stem: "Elastography in ultrasound measures:", options: ["Tissue stiffness to help differentiate benign from malignant lesions","Blood flow velocity","Tissue temperature","Acoustic impedance"], correctIndex: 0, rationale: "Elastography assesses tissue stiffness (strain or shear wave). Malignant lesions tend to be stiffer than benign ones. Used in liver fibrosis staging, breast, and thyroid nodule evaluation.", difficulty: 2, category: "Ultrasound Physics & Instrumentation", topic: "Advanced Techniques" },
  { id: "sono-275", stem: "Shear wave elastography provides:", options: ["Quantitative tissue stiffness measurements in kilopascals (kPa) or meters per second","Qualitative strain ratios only","Color Doppler flow data","Temperature mapping"], correctIndex: 0, rationale: "Shear wave elastography generates shear waves in tissue and measures propagation speed. Stiffer tissue = faster shear wave speed. Provides quantitative values (kPa or m/s) for liver fibrosis staging.", difficulty: 3, category: "Ultrasound Physics & Instrumentation", topic: "Advanced Techniques" },
  { id: "sono-276", stem: "Contrast-enhanced ultrasound (CEUS) uses:", options: ["Microbubble contrast agents that enhance blood pool signal in real-time","Iodinated contrast like CT","Gadolinium-based contrast like MRI","No contrast agent"], correctIndex: 0, rationale: "CEUS uses microbubble agents (gas-filled microspheres) that are purely intravascular. They enhance Doppler signal and B-mode imaging. Used for liver lesion characterization, FAST, and more.", difficulty: 2, category: "Ultrasound Physics & Instrumentation", topic: "Advanced Techniques" },
  { id: "sono-277", stem: "3D/4D ultrasound adds value in obstetrics primarily for:", options: ["Surface rendering of fetal face, evaluation of complex anomalies, and volume measurements","Replacing all 2D scanning","Measuring Doppler velocities more accurately","Eliminating the need for anatomy surveys"], correctIndex: 0, rationale: "3D ultrasound provides volume data for surface rendering (face, limbs), multiplanar reconstruction, and volumetric measurements. 4D adds real-time to 3D. Complements but does not replace 2D.", difficulty: 2, category: "Ultrasound Physics & Instrumentation", topic: "Advanced Techniques" },
  { id: "sono-278", stem: "Point-of-care ultrasound (POCUS) differs from comprehensive exams in that it:", options: ["Is a focused, limited exam answering a specific clinical question at the bedside","Replaces the need for formal sonography","Provides complete organ surveys","Is performed only by sonographers"], correctIndex: 0, rationale: "POCUS is performed by clinicians at the bedside to answer specific binary questions (e.g., free fluid? cardiac activity?). It does not replace comprehensive diagnostic exams.", difficulty: 1, category: "Patient Care & Safety", topic: "Emergency Ultrasound" },
  { id: "sono-279", stem: "Lung ultrasound B-lines indicate:", options: ["Interstitial syndrome (pulmonary edema, interstitial lung disease)","Normal lung","Pneumothorax","Pleural thickening only"], correctIndex: 0, rationale: "B-lines are vertical hyperechoic artifacts arising from the pleural line, extending to screen edge without fading. ≥3 B-lines per intercostal space in bilateral zones indicate interstitial syndrome.", difficulty: 2, category: "Patient Care & Safety", topic: "Emergency Ultrasound" },
  { id: "sono-280", stem: "When obtaining informed consent for an ultrasound-guided procedure, the sonographer should:", options: ["Ensure the ordering physician obtains consent and the patient understands the procedure, risks, and alternatives","Obtain consent independently without physician involvement","Skip consent for ultrasound procedures as they are non-invasive","Only obtain verbal consent"], correctIndex: 0, rationale: "Informed consent for invasive procedures is the physician's responsibility. The sonographer assists by ensuring the patient understands the procedure. Documentation must include risks, benefits, and alternatives.", difficulty: 1, category: "Patient Care & Safety", topic: "Patient Communication" },
  { id: "sono-281", stem: "Proper patient identification before an ultrasound exam includes:", options: ["Using at least two patient identifiers (name and DOB) and verifying the exam order","Using room number only","Asking the patient's age only","Checking only the last name"], correctIndex: 0, rationale: "Two-patient-identifier verification (full name + DOB or MRN) prevents wrong-patient errors. Also verify the exam ordered, indication, and relevant clinical history.", difficulty: 1, category: "Patient Care & Safety", topic: "Patient Communication" },
  { id: "sono-282", stem: "The sonographer notices air in the biliary tree (pneumobilia). This finding is associated with:", options: ["Prior biliary surgery (sphincterotomy, choledochoduodenostomy) or gallstone ileus","Normal finding","Acute cholecystitis","Simple gallstones"], correctIndex: 0, rationale: "Pneumobilia: bright echogenic foci with dirty shadowing/ring-down in the biliary tree. Causes: prior ERCP/sphincterotomy, biliary-enteric anastomosis, or gallstone ileus (gallstone eroding into bowel).", difficulty: 3, category: "Abdominal Sonography", topic: "Gallbladder/Biliary" },
  { id: "sono-283", stem: "The hepatorenal index is used to:", options: ["Quantify hepatic steatosis by comparing liver and renal cortex brightness ratios","Measure kidney size","Assess portal hypertension","Evaluate hepatic vein patency"], correctIndex: 0, rationale: "The hepatorenal index (HRI) is a quantitative ratio of hepatic to renal cortex brightness on B-mode ultrasound. Higher HRI values correlate with greater degrees of hepatic steatosis.", difficulty: 3, category: "Abdominal Sonography", topic: "Liver" },
  { id: "sono-284", stem: "Wunderlich syndrome refers to:", options: ["Spontaneous renal hemorrhage into the subcapsular or perinephric space","Gallstone ileus","Splenic infarction","Pancreatic pseudocyst rupture"], correctIndex: 0, rationale: "Wunderlich syndrome: spontaneous non-traumatic perirenal hemorrhage. Causes include angiomyolipoma, RCC, or vascular malformation. Appears as complex perinephric collection on ultrasound.", difficulty: 4, category: "Abdominal Sonography", topic: "Kidneys" },
  { id: "sono-285", stem: "Renal transplant rejection on ultrasound may show:", options: ["Elevated resistive index (>0.80), enlarged graft, cortical thickening, and reduced corticomedullary differentiation","Normal-sized graft with normal RI","Small hyperechoic graft","Hydronephrosis only"], correctIndex: 0, rationale: "Transplant rejection findings: elevated RI (>0.80), swollen cortex, loss of corticomedullary differentiation, and decreased diastolic flow. Biopsy confirms diagnosis.", difficulty: 3, category: "Abdominal Sonography", topic: "Kidneys" },
  { id: "sono-286", stem: "The normal transplant kidney is placed in:", options: ["The iliac fossa with vascular anastomosis to the iliac vessels","The native kidney bed","The thorax","The retroperitoneal space near the adrenal"], correctIndex: 0, rationale: "Renal transplants are placed in the iliac fossa (extraperitoneal). Renal artery anastomosed to external iliac artery, vein to external iliac vein, and ureter to bladder.", difficulty: 1, category: "Abdominal Sonography", topic: "Kidneys" },
  { id: "sono-287", stem: "Ovarian hyperstimulation syndrome (OHSS) on ultrasound shows:", options: ["Markedly enlarged ovaries with multiple large follicles/cysts and ascites","Normal-sized ovaries","Unilateral small ovary","Absent ovaries"], correctIndex: 0, rationale: "OHSS: bilateral ovarian enlargement with multiple large follicles/cysts, free pelvic and abdominal fluid (ascites), and possible pleural effusion. Complication of fertility treatment.", difficulty: 2, category: "OB/GYN Sonography", topic: "Gynecology" },
  { id: "sono-288", stem: "Asherman syndrome (intrauterine adhesions) may appear as:", options: ["Irregular echogenic bands crossing the endometrial cavity with distortion of normal endometrial stripe","Normal endometrial stripe","Thick homogeneous endometrium","Fluid-filled cavity"], correctIndex: 0, rationale: "Asherman syndrome: intrauterine synechiae (adhesions) from prior instrumentation. Sonohysterography (SHG) shows non-distensible areas and bridging echogenic bands within the cavity.", difficulty: 3, category: "OB/GYN Sonography", topic: "Gynecology" },
  { id: "sono-289", stem: "Saline infusion sonohysterography (SIS) is used to:", options: ["Evaluate the endometrial cavity for polyps, fibroids, and adhesions by distending the cavity with saline","Assess fetal anatomy","Measure cervical length","Evaluate ovarian cysts"], correctIndex: 0, rationale: "SIS: sterile saline instilled into the uterine cavity via catheter provides contrast to evaluate intracavitary pathology (polyps, submucosal fibroids, synechiae). Best performed in proliferative phase.", difficulty: 2, category: "OB/GYN Sonography", topic: "Gynecology" },
  { id: "sono-290", stem: "The S/D ratio of the umbilical artery normally:", options: ["Decreases as pregnancy progresses due to decreasing placental resistance","Increases throughout pregnancy","Remains constant","Is highest at term"], correctIndex: 0, rationale: "As the placenta matures, vascular resistance decreases, increasing diastolic flow. S/D ratio decreases from ~4.0 at 20 weeks to <3.0 at term. Absent/reversed diastolic flow is ominous.", difficulty: 2, category: "OB/GYN Sonography", topic: "Second/Third Trimester" },
  { id: "sono-291", stem: "Absent end-diastolic flow in the umbilical artery is associated with:", options: ["Severe placental insufficiency with high risk of fetal demise","Normal pregnancy","Maternal diabetes","Polyhydramnios"], correctIndex: 0, rationale: "Absent end-diastolic velocity (AEDV) indicates very high placental resistance and severe compromise. Reversed end-diastolic flow (REDV) is even more ominous with imminent fetal death risk.", difficulty: 3, category: "OB/GYN Sonography", topic: "Second/Third Trimester" },
  { id: "sono-292", stem: "Fetal hydronephrosis is considered significant when the AP renal pelvis diameter exceeds:", options: ["7 mm in the second trimester or 10 mm in the third trimester","2 mm at any gestational age","15 mm in the first trimester","20 mm at term"], correctIndex: 0, rationale: "Mild pyelectasis: 4-7mm (second trimester). >7mm or >10mm (third trimester) warrants postnatal follow-up. Associated with UPJ obstruction, VUR, or posterior urethral valves.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-293", stem: "Dandy-Walker malformation on fetal ultrasound shows:", options: ["Cystic dilation of the fourth ventricle, absent or hypoplastic vermis, and enlarged posterior fossa","Normal cerebellum","Absent cerebral hemispheres","Banana-shaped cerebellum"], correctIndex: 0, rationale: "Dandy-Walker: large posterior fossa cyst communicating with the fourth ventricle, hypoplastic/absent cerebellar vermis, and elevated tentorium. May be associated with hydrocephalus.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-294", stem: "Holoprosencephaly is characterized by:", options: ["Failure of the forebrain (prosencephalon) to divide into two hemispheres","Excess division of brain hemispheres","Normal brain with enlarged ventricles","Spinal cord anomaly"], correctIndex: 0, rationale: "Holoprosencephaly: spectrum of forebrain malformation from alobar (most severe: single ventricle, fused thalami) to lobar (partial separation). Associated with trisomy 13 and midline facial defects.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-295", stem: "Fetal echogenic bowel in the second trimester may be associated with:", options: ["Cystic fibrosis, chromosomal abnormality, CMV infection, or swallowed blood","Normal variant only","Renal anomalies","Cardiac defects only"], correctIndex: 0, rationale: "Echogenic bowel (echogenicity ≥ bone) is associated with CF, trisomy 21, intrauterine infection (CMV), IUGR, and swallowed blood. Warrants further workup including CF screening and karyotype.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-296", stem: "Choroid plexus cysts found on second-trimester ultrasound:", options: ["Are usually benign but when combined with other markers may be associated with trisomy 18","Always require amniocentesis","Are diagnostic of Down syndrome","Indicate neural tube defect"], correctIndex: 0, rationale: "Isolated choroid plexus cysts are common (1-2%) and usually resolve by 26 weeks. When associated with other anomalies (clenched fists, cardiac defects), trisomy 18 risk increases.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-297", stem: "The aortic root and pulmonary artery on fetal four-chamber view assessment should:", options: ["Cross each other (great vessel crossover) with the aorta posterior and rightward","Run parallel to each other","Both arise from the left ventricle","Both arise from the right ventricle"], correctIndex: 0, rationale: "Normal great vessels cross: PA anterior and leftward from RV, aorta posterior and rightward from LV. Parallel vessels suggest transposition of great arteries (TGA).", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-298", stem: "Meconium peritonitis on ultrasound appears as:", options: ["Intra-abdominal calcifications with or without ascites due to in utero bowel perforation","Normal fetal abdomen","Polyhydramnios without calcification","Hepatomegaly only"], correctIndex: 0, rationale: "Meconium peritonitis results from fetal bowel perforation. Sterile meconium spills into the peritoneum causing inflammation and calcification. May cause pseudocyst formation.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-299", stem: "An AV fistula created for hemodialysis should mature (develop adequate flow and diameter) within:", options: ["6-8 weeks (rule of 6s: flow >600mL/min, vein >6mm, depth <6mm)","24 hours","6 months","1 year"], correctIndex: 0, rationale: "Rule of 6s for mature AVF: flow volume >600 mL/min, vein diameter >6mm, and depth <6mm from skin. Typically assessed at 6 weeks. Immature fistulas may need intervention.", difficulty: 3, category: "Vascular Sonography", topic: "Dialysis Access" },
  { id: "sono-300", stem: "Proper scanning technique for the neonatal brain uses:", options: ["A high-frequency curvilinear or sector transducer through the anterior fontanelle","A low-frequency linear transducer on the temporal bone","Adult cardiac probe through the mastoid","Endocavitary transducer"], correctIndex: 0, rationale: "Neonatal cranial ultrasound uses the anterior fontanelle as an acoustic window. A small footprint curvilinear or phased array transducer at 7-10 MHz provides excellent brain imaging.", difficulty: 1, category: "Small Parts & Superficial", topic: "Neonatal" },
  { id: "sono-301", stem: "Germinal matrix hemorrhage in premature neonates occurs in the:", options: ["Caudothalamic groove (subependymal region near the head of the caudate nucleus)","Cerebellar vermis","Occipital lobe","Spinal cord"], correctIndex: 0, rationale: "The germinal matrix is highly vascular subependymal tissue near the caudothalamic groove. It is the most common site of intracranial hemorrhage in premature infants. Graded I-IV.", difficulty: 2, category: "Small Parts & Superficial", topic: "Neonatal" },
  { id: "sono-302", stem: "Grade III intraventricular hemorrhage (IVH) is characterized by:", options: ["Intraventricular hemorrhage with acute ventricular dilation (hydrocephalus)","Isolated subependymal hemorrhage","IVH without ventriculomegaly","Periventricular leukomalacia"], correctIndex: 0, rationale: "IVH grading: I = subependymal only, II = IVH without dilation, III = IVH with ventricular dilation, IV = parenchymal hemorrhagic infarction. Higher grades have worse prognosis.", difficulty: 3, category: "Small Parts & Superficial", topic: "Neonatal" },
  { id: "sono-303", stem: "Periventricular leukomalacia (PVL) on neonatal cranial ultrasound appears as:", options: ["Echogenic periventricular white matter that may evolve into cystic lesions","Normal periventricular echogenicity","Hemorrhage in the germinal matrix","Midline brain mass"], correctIndex: 0, rationale: "PVL: ischemic injury to periventricular white matter in premature infants. Initially echogenic, then may become cystic (cystic PVL). Associated with cerebral palsy and developmental delay.", difficulty: 3, category: "Small Parts & Superficial", topic: "Neonatal" },
  { id: "sono-304", stem: "Pyloric stenosis on ultrasound shows:", options: ["Elongated pyloric channel >16mm and muscle wall thickness >3mm","Normal pyloric measurements","Thickened gastric wall only","Duodenal dilation"], correctIndex: 0, rationale: "Hypertrophic pyloric stenosis: muscle thickness >3mm, channel length >16mm, pyloric diameter >13mm. 'Target sign' on transverse view. Presents in infants 2-8 weeks with projectile vomiting.", difficulty: 2, category: "Small Parts & Superficial", topic: "Pediatric" },
  { id: "sono-305", stem: "Intussusception on ultrasound shows:", options: ["Target or doughnut sign on transverse view and pseudokidney sign on longitudinal view","Normal bowel pattern","Free intraperitoneal air","Gallstones"], correctIndex: 0, rationale: "Intussusception: bowel telescoping into itself. Target/doughnut sign (concentric rings of bowel wall) on transverse. Pseudokidney sign on longitudinal. Most common in children 6mo-3yr.", difficulty: 2, category: "Small Parts & Superficial", topic: "Pediatric" },
];
